import java.util.Queue;
import java.util.LinkedList;

public static long solve(long[][] grid, long k) {
    int m = grid.length;
    int n = grid[0].length;
    long count = 0;
    int[][] directions = {{-1, 0}, {1, 0}, {0, -1}, {0, 1}};

    for (int i = 0; i < m; i++) {
        for (int j = 0; j < n; j++) {
            if (grid[i][j] > 0) {
                Queue<int[]> queue = new LinkedList<>();
                queue.add(new int[]{i, j});
                long sum = grid[i][j];
                grid[i][j] = 0;

                while (!queue.isEmpty()) {
                    int[] curr = queue.poll();
                    int x = curr[0];
                    int y = curr[1];
                    for (int[] dir : directions) {
                        int nx = x + dir[0];
                        int ny = y + dir[1];
                        if (nx >= 0 && nx < m && ny >= 0 && ny < n && grid[nx][ny] > 0) {
                            sum += grid[nx][ny];
                            grid[nx][ny] = 0;
                            queue.add(new int[]{nx, ny});
                        }
                    }
                }

                if (sum % k == 0) {
                    count++;
                }
            }
        }
    }

    return count;
}
